export const GLOSSARY = [{"keywords":["2.3l"],"term":"2.3L EcoBoost I-4","body":"Bronco's standard turbocharged 4-cylinder. Roughly 300 hp / 325 lb-ft on premium fuel. The only engine offered with the 7-speed manual."},{"keywords":["2.7l"],"term":"2.7L EcoBoost V6","body":"Twin-turbo V6, about 330 hp / 415 lb-ft. Automatic only. The torque favorite for towing and low-end trail grunt."},{"keywords":["3.0l"],"term":"3.0L EcoBoost V6","body":"Raptor-exclusive twin-turbo V6, ~418 hp / 440 lb-ft. Built for high-speed desert running."},{"keywords":["ecoboost"],"term":"EcoBoost","body":"Ford's family of turbocharged, direct-injection engines — smaller displacement with forced induction for more power per liter."},{"keywords":["7-speed manual"],"term":"7-Speed Manual","body":"Six road gears plus a dedicated low crawler gear for rock-crawling. Available only with the 2.3L engine."},{"keywords":["10-speed automatic"],"term":"10-Speed Automatic","body":"Required for Trail Control, Trail Turn Assist, and Trail One-Pedal Drive. Standard on V6 trims."},{"keywords":["g.o.a.t","terrain management"],"term":"G.O.A.T. Modes","body":"“Goes Over Any Type of Terrain.” Drive modes that retune throttle, traction, steering and 4x4 behavior. Off-road trims get 7 modes vs 5 on standard trims."},{"keywords":["advanced 4x4","automatic on-demand"],"term":"Advanced 4x4 (On-Demand)","body":"Adds an automatic 4WD mode that sends power to the front axle only when needed — usable on dry pavement, unlike part-time 4x4."},{"keywords":["part time selectable"],"term":"Part-Time 4x4","body":"Driver manually selects 2H, 4H or 4L. No full-time/auto mode, so 4WD shouldn't be used on dry pavement."},{"keywords":["locking rear axle","locking front and rear"],"term":"Electronic-Locking Axle","body":"A locker mechanically ties both wheels on an axle together so they turn at the same speed — maximum traction when a wheel lifts off-road."},{"keywords":["hill descent"],"term":"Hill Descent Control","body":"Holds a low, steady speed down steep grades using the brakes, so you can focus on steering."},{"keywords":["trail control"],"term":"Trail Control","body":"Cruise control for off-road: set a low crawl speed and the truck manages throttle and braking while you steer."},{"keywords":["trail turn assist"],"term":"Trail Turn Assist","body":"Brakes the inside rear wheel to dramatically tighten the turning radius on tight trails."},{"keywords":["one-pedal drive"],"term":"Trail One-Pedal Drive","body":"The accelerator controls both acceleration and braking for precise, smooth rock-crawling with one foot."},{"keywords":["stabilizer bar disconnect"],"term":"Stabilizer Bar Disconnect","body":"Electronically disconnects the front sway bar at the push of a button for far greater wheel articulation over obstacles."},{"keywords":["hoss"],"term":"HOSS Suspension","body":"High-Performance Off-Road Stability Suspension. Higher numbers add better dampers — Bilstein on HOSS 2.0, FOX internal-bypass on 3.0, and FOX Live Valve semi-active on the Raptor's HOSS 4.0."},{"keywords":["sasquatch"],"term":"Sasquatch Package","body":"The signature off-road bundle: 35-inch tires, beadlock-capable wheels, electronic-locking front and rear axles, Bilstein dampers and a 4.7 final-drive ratio."},{"keywords":["lux package"],"term":"Lux Package","body":"Top equipment group — bundles premium content like B&O audio, adaptive cruise, 360-degree camera and a heated steering wheel."},{"keywords":["mid package"],"term":"Mid Package","body":"Mid equipment group adding popular convenience and tech features above the base configuration."},{"keywords":["co-pilot360"],"term":"Ford Co-Pilot360","body":"Ford's driver-assist suite: blind-spot monitoring, lane-keeping, pre-collision braking and more."},{"keywords":["pro power onboard"],"term":"Pro Power Onboard","body":"Built-in 400-watt power outlet that runs tools, lights or gear directly off the vehicle."},{"keywords":["b&o sound","bang & olufsen"],"term":"B&O Sound System","body":"Premium 12-speaker audio system tuned by Bang & Olufsen, including a subwoofer."},{"keywords":["fits","integrated tether"],"term":"FITS (Integrated Tether System)","body":"Ford Integrated Tether System — a slot behind the console that accepts modular, swappable accessories like cargo dividers and organizers."},{"keywords":["blis"],"term":"BLIS","body":"Blind Spot Information System with Cross-Traffic Alert — warns of vehicles in your blind spot and when backing out."},{"keywords":["beadlock"],"term":"Beadlock-Capable Wheels","body":"Wheels that can clamp the tire bead to the rim, letting you safely air down to very low pressure for traction on rocks and sand."},{"keywords":["bash plate"],"term":"Bash / Skid Plates","body":"Steel underbody plates that shield the engine, transmission and fuel tank from rocks and trail debris."},{"keywords":["rock rail"],"term":"Rock Rails","body":"Reinforced side rails that protect the body and act as sliders when crossing rocks and ledges."},{"keywords":["swing-gate","swing gate"],"term":"Swing-Gate","body":"Side-hinged rear tailgate that swings open up to 150 degrees and carries the full-size spare tire."},{"keywords":["removable doors and top","dual tops"],"term":"Removable Top & Doors","body":"Doors and roof panels come off for open-air driving. “Dual tops” means you get both a soft top and a hard top."},{"keywords":["marine grade vinyl"],"term":"Marine-Grade Vinyl","body":"Water-resistant, wipe-clean upholstery designed to pair with washout rubber flooring and drain plugs."},{"keywords":["tube doors"],"term":"Tube Doors","body":"Open tubular-frame doors for trail use that keep the airy feel while retaining mirrors. Not street-legal everywhere."},{"keywords":["signature lighting","maker lamp"],"term":"LED Signature Lighting","body":"Distinctive LED accent lighting; some grilles add amber “maker” marker lamps for a retro Bronco look."},{"keywords":["sync 4"],"term":"SYNC 4","body":"Ford's infotainment on a 12-inch touchscreen with pinch-to-zoom and wireless Apple CarPlay / Android Auto."},{"keywords":["sasquatch package"],"term":"Sasquatch Package","body":"35-inch tires, beadlock-capable wheels, locking front and rear axles, and Bilstein dampers."},{"keywords":["360-degree camera","360 camera"],"term":"360-Degree Camera","body":"Stitches multiple cameras into an overhead view for tight parking and spotting trail obstacles."},{"keywords":["adaptive cruise"],"term":"Adaptive Cruise Control","body":"Maintains a set following distance from the vehicle ahead, adjusting speed automatically."},{"keywords":["trailer tow"],"term":"Trailer Tow","body":"Adds wiring, a hitch receiver and trailer sway control for hauling. Prep package wires for a later upfit."},{"keywords":["four-wheel disc brakes"],"term":"4-Wheel Disc Brakes","body":"Disc brakes at all four corners with ABS and electronic stability control for consistent stopping."}];
